<template>
    <div class="m-notice-content">
        <!-- 筛选 & 搜索 -->
        <div class="m-notice-toolbar">
            <div class="m-buttons">
                <span
                    class="u-button"
                    v-for="(item, i) in buttons"
                    :key="i"
                    @click="change(item.value)"
                    :class="[{ active: type == item.value }, item.key]"
                >
                    {{ item.name }}
                </span>
            </div>
            <el-input class="u-search" v-model.lazy="search" placeholder="请输入关键词搜索" clearable></el-input>
        </div>
        <!-- 列表 -->
        <div class="m-notice-box">
            <div class="m-notice-list" v-loading="loading">
                <router-link
                    class="m-list"
                    v-for="(item, i) in list"
                    :key="i"
                    :to="{ name: 'single', params: { id: item.ID } }"
                    target="_blank"
                >
                    <svg width="38" height="38" viewBox="0 0 38 38" xmlns="http://www.w3.org/2000/svg" v-bind:class="'u-icon'" v-bind:svg-inline="''" v-if="item.post_subtype == 3" v-bind:role="'presentation'" v-bind:focusable="'false'" v-bind:tabindex="'-1'"><path d="M19 26.333c.52 0 .955-.176 1.307-.528.35-.35.526-.785.526-1.305v-5.867l1.65 1.65c.336.336.764.505 1.284.505s.947-.169 1.283-.505c.336-.336.504-.764.504-1.283 0-.52-.168-.947-.504-1.283l-4.767-4.767a1.62 1.62 0 00-.596-.39 2.044 2.044 0 00-.687-.114c-.244 0-.474.038-.688.114a1.62 1.62 0 00-.595.39l-4.767 4.767c-.336.336-.504.764-.504 1.283 0 .52.168.947.504 1.283.336.336.764.505 1.283.505.52 0 .947-.169 1.284-.505l1.65-1.65V24.5c0 .52.176.955.528 1.305.35.352.785.528 1.305.528zm0 11c-2.536 0-4.92-.481-7.15-1.444-2.23-.962-4.17-2.268-5.82-3.918-1.65-1.65-2.957-3.59-3.919-5.821C1.148 23.92.667 21.536.667 19c0-2.536.481-4.92 1.444-7.15.962-2.23 2.268-4.17 3.918-5.82 1.65-1.65 3.59-2.957 5.821-3.92C14.08 1.148 16.464.667 19 .667c2.536 0 4.92.48 7.15 1.443 2.23.963 4.17 2.27 5.82 3.92 1.65 1.65 2.957 3.59 3.919 5.82.963 2.23 1.444 4.614 1.444 7.15 0 2.536-.481 4.92-1.444 7.15-.962 2.23-2.268 4.17-3.918 5.82-1.65 1.65-3.59 2.957-5.821 3.919-2.23.963-4.614 1.444-7.15 1.444z"/></svg>
                    <svg width="35" height="38" viewBox="0 0 35 38" xmlns="http://www.w3.org/2000/svg" v-bind:class="'u-icon'" v-bind:svg-inline="''" v-else="" v-bind:role="'presentation'" v-bind:focusable="'false'" v-bind:tabindex="'-1'"><path d="M15.23 10.93L2.098 17.46a3.667 3.667 0 00-1.65 4.916l3.266 6.566a3.666 3.666 0 004.915 1.65l1.642-.816 3.266 6.566a1.833 1.833 0 002.458.825l3.283-1.633a1.833 1.833 0 00.825-2.458l-3.266-6.566 4.924-2.45 11.474 2.484L20.17.281 15.23 10.93zm18.86-1.191c1.396 2.807 1.085 6.135-.838 8.607L26.72 5.214a8.17 8.17 0 017.37 4.525z"/></svg>
                    <span class="u-title"> {{ item.post_title }}</span>
                    <span class="u-time"> {{ showDate(item.post_modified) }}</span>
                </router-link>
            </div>
            <!-- 分页和跳转 -->
            <div class="p-notice-pagination" v-if="pages > 1">
                <el-pagination
                    class="m-pagination"
                    layout="pager"
                    :current-page.sync="page"
                    :page-size="per"
                    :total="total"
                    :pager-count="5"
                    @current-change="changePage"
                    :hide-on-single-page="true"
                />
                <div class="m-jump">
                    <el-input
                        v-model="index"
                        type="number"
                        class="u-input"
                        size="mini"
                        @keyup.enter.native="toJump"
                    ></el-input>
                    <span class="u-jump" @click="toJump">跳转</span>
                </div>
            </div>
        </div>
    </div>
</template>
<script>
import { getPosts } from "@/service/cms";
import { join, pull, cloneDeep, concat } from "lodash";
import { showDate } from "@/utils/moment";
export default {
    name: "NoticeList",
    data: function () {
        return {
            loading: false, //加载状态

            list: [], //数据列表
            page: 1, //当前页数
            total: 1, //总条目数
            pages: 1, //总页数
            per: 10, //每页条目
            index: "", // 跳转页面

            client: this.$store.state.client, //版本选择
            search: "",
            subtype: [1, 2, 3, 4],
            type: "",

            buttons: [
                {
                    name: "全部",
                    key: "",
                    value: "",
                },
                {
                    name: "公告动态",
                    key: "notice",
                    value: 2,
                },
                {
                    name: "运营活动",
                    key: "information",
                    value: 1,
                },
                {
                    name: "功能更新",
                    key: "update",
                    value: 3,
                },
                {
                    name: "兑换通知",
                    key: "message",
                    value: 4,
                },
            ],
        };
    },
    computed: {
        query() {
            return {
                client: this.client,
                search: this.search,
                subtype: !this.type ? "" : this.type,
            };
        },
        clientHeight() {
            return document.documentElement.clientHeight;
        },
        params: function () {
            let params = {
                per: this.per,
                page: ~~this.page || 1,
                sticky: 1,
                ...this.query,
                type: "notice",
            };
            Object.keys(params).forEach((item) => {
                if (!params[item]) delete params[item];
            });
            return params;
        },
    },
    methods: {
        loadPosts: function () {
            this.loading = true;
            getPosts(this.params, this)
                .then((res) => {
                    this.list = res.data.data.list;
                    this.total = res.data.data.total;
                    this.pages = res.data.data.pages;
                })
                .finally(() => {
                    this.loading = false;
                });
        },
        // 去详情页
        toDetail(id) {
            this.$router.push({ name: "single", params: { id } });
            window.scrollTo(0, 0);
        },
        changePage(i) {
            this.page = ~~i;
        },
        // 跳转
        toJump() {
            if (this.index > this.pages) this.index = this.pages;
            if (this.index < 1) this.index = 1;
            this.changePage(this.index);
            this.index = "";
        },
        // 切换类型
        change(key) {
            this.type = key;
            this.page = 1;
            console.log(key);
        },
        showDate,
    },
    watch: {
        params: {
            deep: true,
            immediate: true,
            handler: function (val) {
                this.loadPosts();
            },
        },
        query() {
            this.page = 1;
        },
        clientHeight: {
            immediate: true,
            handler: function (height) {
                if (height > 1024) {
                    this.per = 20;
                    this.page = 1;
                }
            },
        },
    },
    mounted() {},
};
</script>
